import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.DpI_zlPE.js";var i=JSON.parse(`{"title":"主板","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/电脑/legacy/主板.md","filePath":"ccc/电脑/legacy/主板.md"}`),a={name:`ccc/电脑/legacy/主板.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="主板" tabindex="-1">主板 <a class="header-anchor" href="#主板" aria-label="Permalink to “主板”">​</a></h1><h2 id="品牌" tabindex="-1">品牌 <a class="header-anchor" href="#品牌" aria-label="Permalink to “品牌”">​</a></h2><blockquote><p>没有特殊要求，也不追求极限超频的，也懒得研究，微星迫击炮，华硕重炮手，铭瑄电竞之心（堆料性价比较高）。这三款主板一般绰绰有余，一般都能给足200w以上的PL1供电。</p></blockquote><ul><li>微星华硕，硬件互相跟进，实力相近。</li><li>微星华硕针对不同内存颗粒，会自己测一套小参，不会完全沿用公版规范，效能更好。</li><li>铭瑄映泰旗舰主打堆料，公版bios，无功无过，清仓拿下，性价比拉满。</li><li>台独技嘉，台湾制造=粗制滥造，喜欢营销噱头，技嘉团队只做z主板，别的主板就是通路贴牌，买到就是上当。</li><li>华擎花样多，23年国内市场换帅，不知道会不会有大动作，可以看看。</li></ul><p>   微星<a href="https://www.chiphell.com/space-uid-360358.html" target="_blank" rel="noreferrer">Toppc</a> 频道介绍了很多主板细节。通路厂沿用公版bios问题在于，公版是六层pcb，而中低端主板是四层板，要测试团队对预设值进行调校；产品的稳定基本都是因为测试团队提前踩过坑，这也是大厂主板的优势。</p><p>微星在一些设定上会偏保守些，在一定程度上提升了兼容性。华硕很喜欢瞎勾八改名，比如把XMP改名成AI DOCP，跟深度学习没有半毛钱关系硬靠。AI optimized听起来特牛逼，实际上就是给你改成定压定频。</p><p><strong>华硕路子很野</strong>，x3d烧毁归根结底就是华硕一直在偷偷加压，但是毕竟是最大的板厂，没人敢得罪，没人敢说。</p><p>虽然我对华硕观感很差，但也会尊重客观事实，比如华硕b450M PRO-S重炮手，8相drmos Core供电，用料就是很好，我也会推荐。</p><p>  通路厂，换架构初代尽量不要买，比如amd b350通路主板别买，等他出马甲了，比如amd b450，踩过坑了才考虑。</p><blockquote><p>通路厂里铭瑄（马甲梅捷）映泰设计相对合理，七彩虹ODM方案太多，层次不齐。昂达影驰便宜。</p></blockquote><h2 id="高端主板有什么可感知的提升" tabindex="-1">高端主板有什么可感知的提升？ <a class="header-anchor" href="#高端主板有什么可感知的提升" aria-label="Permalink to “高端主板有什么可感知的提升？”">​</a></h2><ul><li>更厚的板层，内存超频更猛。</li><li>超频贴心设计，主板集成开关机按钮，液氮模式。</li><li>供电部分温度会低很多。</li><li>用料更高端。如alc1220集成了数字高通和低通滤波器，参数超过部分独立声卡。</li><li>PCIE切分</li></ul><p>  中端主板目前供电越堆越猛，也有六层板，只要挑对型号，绰绰有余。</p><h2 id="简易判断主板供电好坏" tabindex="-1">简易判断主板供电好坏 <a class="header-anchor" href="#简易判断主板供电好坏" aria-label="Permalink to “简易判断主板供电好坏”">​</a></h2><p>  数电感有偏差，华擎技嘉会装一堆电感虚张声势。看拆机数MOS就行。drmos推荐每相供电工作在25~30w。上下桥分体的mos。每路下桥推荐15w。</p><p>​ 以下方法有效改善供电发热：</p><ul><li>主板供电有散热片</li><li>改善机箱风道</li><li>下压式cpu散热器</li></ul><h3 id="华硕强化并联vs倍相器倍相-被忽略的驱动ic" tabindex="-1">华硕强化并联VS倍相器倍相，被忽略的驱动IC <a class="header-anchor" href="#华硕强化并联vs倍相器倍相-被忽略的驱动ic" aria-label="Permalink to “华硕强化并联VS倍相器倍相，被忽略的驱动IC”">​</a></h3><p>pwm控制芯片和mos管之间还需要驱动电路将PWM脉冲放大到足以驱动功率晶体管。驱动电路虽然发热比较小，但也还是有的。</p><ul><li>上下桥分离mos：驱动电路集成于pwm控制芯片或倍相芯片</li><li>上下桥集成mos：驱动电路集成于pwm控制芯片或倍相芯片</li><li>一体式mos（drmos）：驱动电路集成于mos管</li></ul><p>drmos用不用倍相芯片已经无所谓了。</p><h2 id="主板走线对内存超频的提升" tabindex="-1">主板走线对内存超频的提升 <a class="header-anchor" href="#主板走线对内存超频的提升" aria-label="Permalink to “主板走线对内存超频的提升”">​</a></h2><blockquote><p>板厂没有说的秘密：内存超频与主板的关系：<a href="https://www.bilibili.com/video/BV1ft411y771" target="_blank" rel="noreferrer">BV1ft411y771</a></p><p>板厂没有说的秘密：内存条的深入解析1：<a href="https://www.bilibili.com/video/BV1St411r7VP" target="_blank" rel="noreferrer">BV1St411r7VP</a></p><p>板厂没有说的秘密：内存条的深入解析2 内存的线路与信号差异：<a href="https://www.bilibili.com/video/BV1ft411r7pC" target="_blank" rel="noreferrer">BV1ft411r7pC</a></p><p>板厂没有说的秘密：内存条体质是如何定义的与在不同主板的差异：<a href="https://www.bilibili.com/video/BV1At411a7YV" target="_blank" rel="noreferrer">BV1At411a7YV</a></p><p>林老师讲堂：常见的内存误区~搞懂内存的名词跟架构入门要点！：<a href="https://www.bilibili.com/video/BV15t411M7QK" target="_blank" rel="noreferrer">BV15t411M7QK</a></p><p>板厂没有说的秘密：迎接下一世代——再次科普内存走线的差异！<a href="https://www.bilibili.com/video/BV1ke411W7jX" target="_blank" rel="noreferrer">BV1ke411W7jX</a></p></blockquote><p>内存走线目前主要分为 菊花链（daisy chain）和T型拓扑（T-type）。 家用平台4个内存槽的 菊花链插两根离cpu远的槽，内存超频性能最强。T型拓扑（T-type）插满四根的话比菊花链略强，但是插两根极烂。这种强弱的体现有可能在于频率一样，但是小参可以拉的更紧。ddr4要到4000+频率走线上的差异开始变得明显。 AMD x570公版指导方案是菊花链走线。英特尔公版指导方案还是T型拓扑。</p><p>X570和B550三大厂都是菊花链，只有华擎是T型拓扑，但是华擎X570phantom x,creator和aqua是菊花链，B550情况不明，可以自行看板子和华擎以前的X470，B450长的是不是一样的，长的一样就是沿用老的Layout还是T型拓扑，X570之后新开案的才是菊花链。映泰七彩虹那些奇奇怪怪的我推测应该是公版方案菊花链。</p><p>x470微星，c8h,prime pro是菊花链，其余基本t拓扑。b450技嘉是t拓扑，微星可能是菊花链，华硕可能是t拓扑。 z370包括z370之前基本都是t type，z370疑似华擎是菊花链，z390开始微星是菊花链，z490疑似三大厂都是菊花链。</p><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to “参考链接”">​</a></h2><ul><li><p><a href="http://www.smxdiy.com" target="_blank" rel="noreferrer">smxdiy</a> 垃圾佬的最爱，魔改交流论坛。</p></li><li><p><a href="https://space.bilibili.com/431211331" target="_blank" rel="noreferrer">MSI工程师林大B站号</a>深入了解超频知识和MSI新品表现以及板U上的细节，能了解很多。</p></li><li><p><a href="https://www.chiphell.com/forum.php?mod=viewthread&amp;tid=2225286" target="_blank" rel="noreferrer">chiphell@londbell整理的b550主板供电一览</a></p></li><li><p><a href="https://docs.google.com/spreadsheets/d/1wmsTYK9Z3-jUX5LGRoFnsZYZiW1pfiDZnKCjaXyzd1o/edit#gid=2112472504" target="_blank" rel="noreferrer">raisonjohn整理的AM4接口主板详情</a>这位老哥整理的特别好，可惜要科学上网，也没有LGA1200。</p></li><li><p><a href="https://www.hardwareluxx.de/community/threads/amd-3rd-gen-am4-mainboards-vrm-liste-x570-pro565-b550-a520.1228904/#2.3" target="_blank" rel="noreferrer">hardwareluxx整理的amd主板供电一览</a></p></li><li><p><a href="https://docs.google.com/spreadsheets/d/1IY6W6YhyjnzSvi8BqEqiK1xykSiTDF2Lt1FO8cNhI6I/edit#gid=585498417" target="_blank" rel="noreferrer">raisonjohn整理的LGA1151接口主板详情</a>(Z390/Z370/H370/B365/B360/H310)（这位老哥整理的特别好，可惜要科学上网，也没有LGA1200）</p></li><li><p><a href="https://docs.google.com/spreadsheets/d/16YJm4L1-ohpL8s-4rLDDDCBZvi97ZYwkc44s7LS5-2Q/edit#gid=0" target="_blank" rel="noreferrer">asdkj1740整理的Z490/Z590 VRM</a>（可读性不是很好）</p></li><li><p><a href="https://docs.google.com/spreadsheets/d/1yPS3hj_K7EPT4RBWCyjdKNP56pnwDz-IgBc0975-FUg/edit#gid=0" target="_blank" rel="noreferrer">qhfreddy整理的LGA1200主板供电一览</a>（做了一半，期待更新）</p></li></ul>`,28)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};